This is a comprehensive E-E-A-T Builder page for CitedBy.ai with 7 tabs. It allows users to audit their E-E-A-T signals and generate optimized content. The design follows the existing dark theme (bg-[#0a0a0f], glass-panel, emerald primary, font-serif headings).

Write the COMPLETE file below using the Write tool to C:\Users\User\SaaSV2\pages\EeatBuilder.tsx:

```tsx
import React, { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import {
  ArrowLeft, Shield, BookOpen, Award, Lock, Search, Loader2, CheckCircle2,
  AlertTriangle, XCircle, ArrowRight, Zap, Copy, Check, Download, Code2,
  History, Wrench, FileCode, ChevronRight, TrendingUp, TrendingDown, ExternalLink
} from 'lucide-react';
import { User } from '../types';
import {
  EEATAuditResult, EEATFinding, EEATHistoryEntry,
  runEEATAudit, getAuditHistory, compareAudits
} from '../services/eeat/eeat-auditor';

interface EeatBuilderProps {
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onBack: () => void;
}

type TabId = 'audit' | 'citation-block' | 'author-bio' | 'trust-signals' | 'about-page' | 'export' | 'history';

const TABS: { id: TabId; label: string; icon: React.ReactNode }[] = [
  { id: 'audit', label: 'Audit E-E-A-T', icon: <Search size={16} /> },
  { id: 'citation-block', label: 'Citation Block', icon: <BookOpen size={16} /> },
  { id: 'author-bio', label: 'Author Bio', icon: <Award size={16} /> },
  { id: 'trust-signals', label: 'Trust Signals', icon: <Shield size={16} /> },
  { id: 'about-page', label: 'About Page', icon: <Lock size={16} /> },
  { id: 'export', label: 'Export CMS', icon: <FileCode size={16} /> },
  { id: 'history', label: 'Historique', icon: <History size={16} /> },
];

const PILLAR_COLORS: Record<string, string> = {
  experience: '#f59e0b',
  expertise: '#3b82f6',
  authority: '#8b5cf6',
  trust: '#10b981'
};

const PILLAR_LABELS: Record<string, string> = {
  experience: 'Expérience',
  expertise: 'Expertise',
  authority: 'Autorité',
  trust: 'Confiance'
};

// Export format wrapper
const wrapForCMS = (content: string, format: 'html' | 'wordpress' | 'webflow'): string => {
  switch (format) {
    case 'wordpress':
      return `<!-- wp:html -->\n${content}\n<!-- /wp:html -->`;
    case 'webflow':
      return `<div class="w-embed">\n${content}\n</div>`;
    default:
      return content;
  }
};

const EeatBuilder: React.FC<EeatBuilderProps> = ({ user, onDeductCredits, onBack }) => {
  const [activeTab, setActiveTab] = useState<TabId>('audit');

  // Audit state
  const [auditUrl, setAuditUrl] = useState('');
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditResult, setAuditResult] = useState<EEATAuditResult | null>(null);

  // Generator states
  const [generatedContent, setGeneratedContent] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState<string | null>(null);
  const [copied, setCopied] = useState<string | null>(null);

  // History state
  const [history, setHistory] = useState<EEATHistoryEntry[]>([]);

  // Export state
  const [exportFormat, setExportFormat] = useState<'html' | 'wordpress' | 'webflow'>('html');
  const [lastExportContent, setLastExportContent] = useState('');

  useEffect(() => {
    setHistory(getAuditHistory());
  }, [auditResult]);

  const handleAudit = async () => {
    if (!auditUrl) return;
    setIsAuditing(true);
    try {
      const result = await runEEATAudit(auditUrl);
      setAuditResult(result);
    } catch (error) {
      console.error('Audit failed:', error);
    } finally {
      setIsAuditing(false);
    }
  };

  const handleGenerateContent = async (tool: string) => {
    if (!user) {
      alert('Veuillez vous connecter.');
      return;
    }
    if (user.credits < 5) {
      alert('Crédits insuffisants.');
      return;
    }
    const success = onDeductCredits(5);
    if (!success) return;

    setIsGenerating(tool);

    await new Promise(resolve => setTimeout(resolve, 2000));

    const brandName = auditUrl ? new URL(auditUrl).hostname : 'votre-marque';

    const templates: Record<string, string> = {
      'citation-block': `<blockquote class="citation-block" itemscope itemtype="https://schema.org/Review">
  <p itemprop="reviewBody">"${brandName} a transformé notre approche digitale. Les résultats ont dépassé nos attentes avec une augmentation de 45% de notre visibilité en ligne."</p>
  <footer>
    <cite itemprop="author" itemscope itemtype="https://schema.org/Person">
      <span itemprop="name">Marie Dupont</span>
    </cite>
    <span itemprop="jobTitle">Directrice Marketing</span>,
    <span itemprop="worksFor">TechCorp France</span>
  </footer>
  <meta itemprop="datePublished" content="${new Date().toISOString().split('T')[0]}" />
</blockquote>`,
      'author-bio': `<div class="author-bio" itemscope itemtype="https://schema.org/Person">
  <img itemprop="image" src="/images/author.jpg" alt="Photo de l'auteur" />
  <div class="author-info">
    <h3 itemprop="name">Dr. Jean Martin</h3>
    <p itemprop="jobTitle">Expert en Stratégie Digitale</p>
    <p itemprop="description">Avec plus de 15 ans d'expérience en optimisation digitale, Dr. Martin accompagne les entreprises dans leur transformation numérique. Certifié Google Analytics et HubSpot, il a publié plus de 50 articles dans des revues spécialisées.</p>
    <div class="author-credentials">
      <span itemprop="knowsAbout">SEO</span>
      <span itemprop="knowsAbout">AEO</span>
      <span itemprop="knowsAbout">Marketing Digital</span>
    </div>
    <link itemprop="sameAs" href="https://linkedin.com/in/jeanmartin" />
    <link itemprop="sameAs" href="https://twitter.com/jeanmartin" />
  </div>
</div>`,
      'trust-signals': `<script type="application/ld+json">
{
  "@context": "https://schema.org",
  "@type": "Organization",
  "name": "${brandName}",
  "url": "https://${brandName}",
  "logo": "https://${brandName}/logo.png",
  "sameAs": [
    "https://linkedin.com/company/${brandName}",
    "https://twitter.com/${brandName}"
  ],
  "knowsAbout": ["AEO", "SEO", "Marketing Digital"],
  "hasCredential": {
    "@type": "EducationalOccupationalCredential",
    "credentialCategory": "certification",
    "name": "Google Partner Certifié"
  },
  "aggregateRating": {
    "@type": "AggregateRating",
    "ratingValue": "4.8",
    "reviewCount": "127"
  }
}
</script>`,
      'about-page': `<article class="about-page" itemscope itemtype="https://schema.org/AboutPage">
  <header>
    <h1 itemprop="name">À Propos de ${brandName}</h1>
    <p itemprop="description">Fondée en 2020, ${brandName} est la plateforme de référence pour l'optimisation de la visibilité sur les moteurs de réponse IA.</p>
  </header>

  <section class="mission">
    <h2>Notre Mission</h2>
    <p>Nous aidons les entreprises à devenir la source de référence citée par ChatGPT, Claude, Perplexity et Gemini. Notre technologie analyse plus de 50 critères AEO pour maximiser votre présence dans les réponses génératives.</p>
  </section>

  <section class="team" itemscope itemtype="https://schema.org/Organization">
    <h2>Notre Équipe</h2>
    <p>Une équipe de <span itemprop="numberOfEmployees">15</span> experts en IA, SEO et développement web.</p>
    <meta itemprop="foundingDate" content="2020-01-15" />
    <meta itemprop="foundingLocation" content="Paris, France" />
  </section>

  <section class="contact">
    <h2>Nous Contacter</h2>
    <p>Email: <a href="mailto:contact@${brandName}">contact@${brandName}</a></p>
    <p>Adresse: 42 Rue de la Tech, 75008 Paris, France</p>
  </section>
</article>`
    };

    setGeneratedContent(prev => ({ ...prev, [tool]: templates[tool] || '' }));
    setIsGenerating(null);
  };

  const handleCopy = (key: string, content: string) => {
    const wrapped = wrapForCMS(content, exportFormat);
    navigator.clipboard.writeText(wrapped);
    setCopied(key);
    setTimeout(() => setCopied(null), 2000);
  };

  const handleDownloadHtml = (filename: string, content: string) => {
    const wrapped = wrapForCMS(content, exportFormat);
    const blob = new Blob([wrapped], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${filename}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // Navigate to a specific tool tab with auto-generate
  const handleFixFromAudit = (fixTool: string) => {
    setActiveTab(fixTool as TabId);
    // Auto-generate if not already generated
    if (!generatedContent[fixTool]) {
      handleGenerateContent(fixTool);
    }
  };

  // Count fixable issues
  const fixableIssues = auditResult?.findings.filter(f => f.status !== 'present' && f.fixTool) || [];
  const totalFixCost = fixableIssues.length * 5;

  const handleFixAll = async () => {
    if (!user || user.credits < totalFixCost) {
      alert(`Crédits insuffisants. Il faut ${totalFixCost} Gas pour tout corriger.`);
      return;
    }
    for (const finding of fixableIssues) {
      if (finding.fixTool && !generatedContent[finding.fixTool]) {
        await handleGenerateContent(finding.fixTool);
      }
    }
  };

  // --- Render Helpers ---

  const renderStatusIcon = (status: string) => {
    if (status === 'present') return <CheckCircle2 size={16} className="text-emerald-400" />;
    if (status === 'incomplete') return <AlertTriangle size={16} className="text-amber-400" />;
    return <XCircle size={16} className="text-red-400" />;
  };

  const renderExportPanel = (key: string, content: string) => (
    <div className="mt-4 space-y-3">
      {/* Format selector */}
      <div className="flex items-center gap-2">
        <span className="text-xs text-gray-500">Format :</span>
        {(['html', 'wordpress', 'webflow'] as const).map(fmt => (
          <button
            key={fmt}
            onClick={() => setExportFormat(fmt)}
            className={`text-xs px-3 py-1 rounded-lg transition-all ${
              exportFormat === fmt
                ? 'bg-primary text-black font-bold'
                : 'bg-white/5 text-gray-400 hover:bg-white/10'
            }`}
          >
            {fmt === 'html' ? 'HTML brut' : fmt === 'wordpress' ? 'WordPress' : 'Webflow'}
          </button>
        ))}
      </div>
      {/* Code block */}
      <div className="relative">
        <pre className="bg-black/40 border border-white/10 rounded-xl p-4 text-sm text-gray-300 overflow-x-auto max-h-64 font-mono">
          {wrapForCMS(content, exportFormat)}
        </pre>
      </div>
      {/* Action buttons */}
      <div className="flex gap-2">
        <button
          onClick={() => handleCopy(key, content)}
          className="flex items-center gap-1.5 text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-3 py-2 rounded-lg transition-colors text-gray-300"
        >
          {copied === key ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
          {copied === key ? 'Copié !' : 'Copier'}
        </button>
        <button
          onClick={() => handleDownloadHtml(key, content)}
          className="flex items-center gap-1.5 text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-3 py-2 rounded-lg transition-colors text-gray-300"
        >
          <Download size={12} /> Télécharger .html
        </button>
      </div>
    </div>
  );

  const renderGeneratorTab = (toolId: string, title: string, description: string) => (
    <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
      <div className="glass-panel p-6 rounded-xl border border-white/10">
        <h3 className="text-lg font-semibold text-white mb-2">{title}</h3>
        <p className="text-sm text-gray-400 mb-4">{description}</p>

        {!generatedContent[toolId] ? (
          <button
            onClick={() => handleGenerateContent(toolId)}
            disabled={isGenerating === toolId}
            className="px-6 py-3 bg-primary text-black font-bold rounded-xl hover:brightness-110 transition-all flex items-center gap-2"
          >
            {isGenerating === toolId ? (
              <><Loader2 size={16} className="animate-spin" /> Génération...</>
            ) : (
              <><Zap size={16} /> Générer (5 Gas)</>
            )}
          </button>
        ) : (
          <div>
            <div className="flex items-center gap-2 text-sm text-emerald-400 mb-3">
              <CheckCircle2 size={14} />
              Contenu généré avec succès
            </div>
            {renderExportPanel(toolId, generatedContent[toolId])}
          </div>
        )}
      </div>
    </div>
  );

  // --- Main Render ---
  return (
    <div className="max-w-6xl mx-auto px-4 py-8 animate-in fade-in duration-500">
      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      <div className="mb-8">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-10 rounded-xl bg-violet-500/20 flex items-center justify-center">
            <Shield size={20} className="text-violet-400" />
          </div>
          <h1 className="text-3xl font-serif font-bold text-white">E-E-A-T Builder</h1>
        </div>
        <p className="text-gray-400">Auditez et améliorez vos signaux Experience, Expertise, Authoritativeness, Trust.</p>
      </div>

      {/* Workflow Banner */}
      {auditResult && fixableIssues.length > 0 && activeTab === 'audit' && (
        <div className="mb-6 bg-amber-500/10 border border-amber-500/20 rounded-xl p-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Wrench size={18} className="text-amber-400" />
            <span className="text-sm text-white">
              <strong>{fixableIssues.length} problèmes détectés</strong> peuvent être corrigés automatiquement
            </span>
          </div>
          <button
            onClick={handleFixAll}
            className="text-xs bg-amber-500 text-black font-bold px-4 py-2 rounded-lg hover:brightness-110 transition-all flex items-center gap-1"
          >
            Tout corriger ({totalFixCost} Gas) <ArrowRight size={12} />
          </button>
        </div>
      )}

      {/* Tab Navigation */}
      <div className="mb-8 overflow-x-auto">
        <div className="inline-flex bg-white/5 p-1.5 rounded-2xl border border-white/10">
          {TABS.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2.5 rounded-xl text-sm font-medium transition-all duration-300 flex items-center gap-2 whitespace-nowrap ${
                activeTab === tab.id
                  ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.2)] font-bold'
                  : 'text-gray-400 hover:text-white hover:bg-white/5'
              }`}
            >
              <span className={activeTab === tab.id ? '' : 'opacity-50'}>{tab.icon}</span>
              <span className="hidden md:inline">{tab.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Tab Content */}
      <div>
        {/* AUDIT TAB */}
        {activeTab === 'audit' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
            {/* Audit Input */}
            <div className="glass-panel p-6 rounded-xl border border-white/10">
              <h3 className="text-lg font-semibold text-white mb-4">Audit E-E-A-T de votre site</h3>
              <div className="flex gap-3">
                <input
                  type="url"
                  value={auditUrl}
                  onChange={e => setAuditUrl(e.target.value)}
                  placeholder="https://votre-site.com"
                  className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder-gray-500 focus:border-primary/50 focus:outline-none"
                />
                <button
                  onClick={handleAudit}
                  disabled={isAuditing || !auditUrl}
                  className="px-6 py-3 bg-primary text-black font-bold rounded-xl hover:brightness-110 transition-all flex items-center gap-2 disabled:opacity-50"
                >
                  {isAuditing ? <Loader2 size={16} className="animate-spin" /> : <Search size={16} />}
                  {isAuditing ? 'Analyse...' : 'Auditer'}
                </button>
              </div>
            </div>

            {/* Audit Results */}
            {auditResult && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {/* Score Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  {(['experience', 'expertise', 'authority', 'trust'] as const).map(pillar => (
                    <div key={pillar} className="glass-panel p-5 rounded-xl border border-white/10 text-center">
                      <p className="text-xs uppercase tracking-wider mb-2" style={{ color: PILLAR_COLORS[pillar] }}>
                        {PILLAR_LABELS[pillar]}
                      </p>
                      <p className="text-3xl font-bold text-white">{auditResult.scores[pillar]}</p>
                      <div className="h-1.5 bg-white/10 rounded-full mt-3">
                        <div
                          className="h-full rounded-full transition-all duration-700"
                          style={{ width: `${auditResult.scores[pillar]}%`, backgroundColor: PILLAR_COLORS[pillar] }}
                        />
                      </div>
                    </div>
                  ))}
                </div>

                {/* Findings List */}
                <div className="glass-panel rounded-xl border border-white/10">
                  <div className="p-5 border-b border-white/5">
                    <h3 className="text-lg font-semibold text-white">Résultats détaillés</h3>
                  </div>
                  <div className="divide-y divide-white/5">
                    {auditResult.findings.map((finding, i) => (
                      <div key={i} className="p-4 flex items-center justify-between hover:bg-white/[0.02] transition-colors">
                        <div className="flex items-center gap-3 flex-1">
                          {renderStatusIcon(finding.status)}
                          <div>
                            <p className="text-sm font-medium text-white">{finding.label}</p>
                            <p className="text-xs text-gray-500">{finding.description}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          <span
                            className="text-[10px] uppercase tracking-wider px-2 py-0.5 rounded-full font-bold"
                            style={{ color: PILLAR_COLORS[finding.pillar], backgroundColor: PILLAR_COLORS[finding.pillar] + '15' }}
                          >
                            {PILLAR_LABELS[finding.pillar]}
                          </span>
                          {finding.status !== 'present' && finding.fixTool && (
                            <button
                              onClick={() => handleFixFromAudit(finding.fixTool!)}
                              className="text-xs bg-primary/10 text-primary hover:bg-primary/20 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
                            >
                              <Wrench size={12} /> Corriger
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* GENERATOR TABS */}
        {activeTab === 'citation-block' && renderGeneratorTab(
          'citation-block',
          'Bloc de Citation Client',
          'Générez des blocs de témoignages structurés avec Schema.org pour démontrer l\'expérience utilisateur.'
        )}
        {activeTab === 'author-bio' && renderGeneratorTab(
          'author-bio',
          'Biographie Auteur Expert',
          'Créez une biographie auteur complète avec données structurées pour renforcer votre expertise.'
        )}
        {activeTab === 'trust-signals' && renderGeneratorTab(
          'trust-signals',
          'Signaux de Confiance (Trust Signals)',
          'Générez les données structurées Organization Schema.org pour établir votre autorité.'
        )}
        {activeTab === 'about-page' && renderGeneratorTab(
          'about-page',
          'Page À Propos Optimisée',
          'Créez une page About complète et structurée pour maximiser la confiance des IA.'
        )}

        {/* EXPORT CMS TAB */}
        {activeTab === 'export' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
            <div className="glass-panel p-6 rounded-xl border border-white/10">
              <h3 className="text-lg font-semibold text-white mb-2">Export CMS</h3>
              <p className="text-sm text-gray-400 mb-6">
                Exportez vos contenus générés au format adapté à votre CMS.
              </p>

              {/* Format selector */}
              <div className="flex gap-3 mb-6">
                {([
                  { id: 'html' as const, label: 'HTML Brut', desc: 'Code HTML standard' },
                  { id: 'wordpress' as const, label: 'WordPress Shortcode', desc: 'Bloc wp:html' },
                  { id: 'webflow' as const, label: 'Webflow Embed', desc: 'Div w-embed' },
                ] as const).map(fmt => (
                  <button
                    key={fmt.id}
                    onClick={() => setExportFormat(fmt.id)}
                    className={`flex-1 p-4 rounded-xl border text-left transition-all ${
                      exportFormat === fmt.id
                        ? 'border-primary/50 bg-primary/5'
                        : 'border-white/10 bg-white/[0.02] hover:border-white/20'
                    }`}
                  >
                    <p className={`text-sm font-bold ${exportFormat === fmt.id ? 'text-primary' : 'text-white'}`}>{fmt.label}</p>
                    <p className="text-xs text-gray-500 mt-1">{fmt.desc}</p>
                  </button>
                ))}
              </div>

              {/* List generated content */}
              {Object.keys(generatedContent).length === 0 ? (
                <div className="text-center py-12 text-gray-500">
                  <FileCode size={48} className="mx-auto mb-3 opacity-20" />
                  <p className="text-sm">Aucun contenu généré. Utilisez les onglets pour générer du contenu d'abord.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  {Object.entries(generatedContent).map(([key, content]) => (
                    <div key={key} className="border border-white/10 rounded-xl p-4">
                      <div className="flex items-center justify-between mb-3">
                        <h4 className="text-sm font-bold text-white capitalize">{key.replace('-', ' ')}</h4>
                        <div className="flex gap-2">
                          <button
                            onClick={() => handleCopy(key, content)}
                            className="flex items-center gap-1 text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-3 py-1.5 rounded-lg text-gray-300"
                          >
                            {copied === key ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
                            {copied === key ? 'Copié !' : 'Copier'}
                          </button>
                          <button
                            onClick={() => handleDownloadHtml(key, content)}
                            className="flex items-center gap-1 text-xs bg-primary text-black font-bold px-3 py-1.5 rounded-lg"
                          >
                            <Download size={12} /> .html
                          </button>
                        </div>
                      </div>
                      <pre className="bg-black/40 border border-white/10 rounded-lg p-3 text-xs text-gray-400 overflow-x-auto max-h-40 font-mono">
                        {wrapForCMS(content, exportFormat)}
                      </pre>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* HISTORY TAB */}
        {activeTab === 'history' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
            {history.length === 0 ? (
              <div className="glass-panel p-12 rounded-xl border border-white/10 text-center text-gray-500">
                <History size={48} className="mx-auto mb-3 opacity-20" />
                <p className="text-sm">Aucun audit dans l'historique. Lancez votre premier audit E-E-A-T.</p>
                <button
                  onClick={() => setActiveTab('audit')}
                  className="mt-4 text-primary hover:text-white transition-colors text-sm flex items-center gap-1 mx-auto"
                >
                  Lancer un audit <ArrowRight size={14} />
