                          {finding.status !== 'present' && finding.fixTool && (
                            <button
                              onClick={() => handleFixFromAudit(finding.fixTool!)}
                              className="text-xs bg-primary/10 text-primary hover:bg-primary/20 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
                            >
                              <Wrench size={12} /> Corriger
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* GENERATOR TABS */}
        {activeTab === 'citation-block' && renderGeneratorTab(
          'citation-block',
          'Bloc de Citation Client',
          'Générez des blocs de témoignages structurés avec Schema.org pour démontrer l\'expérience utilisateur.'
        )}
        {activeTab === 'author-bio' && renderGeneratorTab(
          'author-bio',
          'Biographie Auteur Expert',
          'Créez une biographie auteur complète avec données structurées pour renforcer votre expertise.'
        )}
        {activeTab === 'trust-signals' && renderGeneratorTab(
          'trust-signals',
          'Signaux de Confiance (Trust Signals)',
          'Générez les données structurées Organization Schema.org pour établir votre autorité.'
        )}
        {activeTab === 'about-page' && renderGeneratorTab(
          'about-page',
          'Page À Propos Optimisée',
          'Créez une page About complète et structurée pour maximiser la confiance des IA.'
        )}

        {/* EXPORT CMS TAB */}
        {activeTab === 'export' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
            <div className="glass-panel p-6 rounded-xl border border-white/10">
              <h3 className="text-lg font-semibold text-white mb-2">Export CMS</h3>
              <p className="text-sm text-gray-400 mb-6">
                Exportez vos contenus générés au format adapté à votre CMS.
              </p>

              {/* Format selector */}
              <div className="flex gap-3 mb-6">
                {([
                  { id: 'html' as const, label: 'HTML Brut', desc: 'Code HTML standard' },
                  { id: 'wordpress' as const, label: 'WordPress Shortcode', desc: 'Bloc wp:html' },
                  { id: 'webflow' as const, label: 'Webflow Embed', desc: 'Div w-embed' },
                ] as const).map(fmt => (
                  <button
                    key={fmt.id}
                    onClick={() => setExportFormat(fmt.id)}
                    className={`flex-1 p-4 rounded-xl border text-left transition-all ${
                      exportFormat === fmt.id
                        ? 'border-primary/50 bg-primary/5'
                        : 'border-white/10 bg-white/[0.02] hover:border-white/20'
                    }`}
                  >
                    <p className={`text-sm font-bold ${exportFormat === fmt.id ? 'text-primary' : 'text-white'}`}>{fmt.label}</p>
                    <p className="text-xs text-gray-500 mt-1">{fmt.desc}</p>
                  </button>
                ))}
              </div>

              {/* List generated content */}
              {Object.keys(generatedContent).length === 0 ? (
                <div className="text-center py-12 text-gray-500">
                  <FileCode size={48} className="mx-auto mb-3 opacity-20" />
                  <p className="text-sm">Aucun contenu généré. Utilisez les onglets pour générer du contenu d'abord.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  {Object.entries(generatedContent).map(([key, content]) => (
                    <div key={key} className="border border-white/10 rounded-xl p-4">
                      <div className="flex items-center justify-between mb-3">
                        <h4 className="text-sm font-bold text-white capitalize">{key.replace('-', ' ')}</h4>
                        <div className="flex gap-2">
                          <button
                            onClick={() => handleCopy(key, content)}
                            className="flex items-center gap-1 text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-3 py-1.5 rounded-lg text-gray-300"
                          >
                            {copied === key ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
                            {copied === key ? 'Copié !' : 'Copier'}
                          </button>
                          <button
                            onClick={() => handleDownloadHtml(key, content)}
                            className="flex items-center gap-1 text-xs bg-primary text-black font-bold px-3 py-1.5 rounded-lg"
                          >
                            <Download size={12} /> .html
                          </button>
                        </div>
                      </div>
                      <pre className="bg-black/40 border border-white/10 rounded-lg p-3 text-xs text-gray-400 overflow-x-auto max-h-40 font-mono">
                        {wrapForCMS(content, exportFormat)}
                      </pre>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* HISTORY TAB */}
        {activeTab === 'history' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
            {history.length === 0 ? (
              <div className="glass-panel p-12 rounded-xl border border-white/10 text-center text-gray-500">
                <History size={48} className="mx-auto mb-3 opacity-20" />
                <p className="text-sm">Aucun audit dans l'historique. Lancez votre premier audit E-E-A-T.</p>
                <button
                  onClick={() => setActiveTab('audit')}
                  className="mt-4 text-primary hover:text-white transition-colors text-sm flex items-center gap-1 mx-auto"
                >
                  Lancer un audit <ArrowRight size={14} />
                </button>
              </div>
            ) : (
              <>
                {/* Evolution Chart */}
                {history.length >= 2 && (
                  <div className="glass-panel p-6 rounded-xl border border-white/10">
                    <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                      <TrendingUp size={18} className="text-primary" />
                      Évolution des scores E-E-A-T
                    </h3>
                    <div className="h-64">
                      <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={history.slice(0, 10).reverse().map(h => ({
                          date: new Date(h.result.timestamp).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' }),
                          ...h.result.scores,
                          global: h.result.globalScore
                        }))}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" />
                          <XAxis dataKey="date" tick={{ fill: '#6b7280', fontSize: 11 }} />
                          <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} domain={[0, 100]} />
                          <Tooltip contentStyle={{ backgroundColor: '#1a1a2e', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '12px', color: 'white' }} />
                          <Legend />
                          {Object.entries(PILLAR_COLORS).map(([key, color]) => (
                            <Line key={key} type="monotone" dataKey={key} stroke={color} strokeWidth={2} dot={{ r: 3 }} name={PILLAR_LABELS[key]} />
                          ))}
                        </LineChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                )}

                {/* Before/After Cards */}
                {history.length >= 2 && (() => {
                  const latest = history[0].result;
                  const previous = history[1].result;
                  const deltas = compareAudits(latest, previous);

                  return (
                    <div className="glass-panel p-6 rounded-xl border border-white/10">
                      <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                        <ChevronRight size={18} className="text-amber-400" />
                        Comparaison : Dernier vs Précédent
                      </h3>
                      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                        {(['experience', 'expertise', 'authority', 'trust'] as const).map(pillar => (
                          <div key={pillar} className="bg-white/5 p-4 rounded-xl text-center">
                            <p className="text-xs uppercase tracking-wider mb-2" style={{ color: PILLAR_COLORS[pillar] }}>
                              {PILLAR_LABELS[pillar]}
                            </p>
                            <p className="text-2xl font-bold text-white">{latest.scores[pillar]}</p>
                            <p className={`text-sm font-bold mt-1 flex items-center justify-center gap-1 ${
                              deltas[pillar] > 0 ? 'text-emerald-400' : deltas[pillar] < 0 ? 'text-red-400' : 'text-gray-500'
                            }`}>
                              {deltas[pillar] > 0 ? <TrendingUp size={12} /> : deltas[pillar] < 0 ? <TrendingDown size={12} /> : null}
                              {deltas[pillar] > 0 ? '+' : ''}{deltas[pillar]} pts
                            </p>
                          </div>
                        ))}
                        <div className="bg-primary/5 border border-primary/20 p-4 rounded-xl text-center">
                          <p className="text-xs uppercase tracking-wider mb-2 text-primary">Global</p>
                          <p className="text-2xl font-bold text-white">{latest.globalScore}</p>
                          <p className={`text-sm font-bold mt-1 flex items-center justify-center gap-1 ${
                            deltas.global > 0 ? 'text-emerald-400' : deltas.global < 0 ? 'text-red-400' : 'text-gray-500'
                          }`}>
                            {deltas.global > 0 ? <TrendingUp size={12} /> : deltas.global < 0 ? <TrendingDown size={12} /> : null}
                            {deltas.global > 0 ? '+' : ''}{deltas.global} pts
                          </p>
                        </div>
                      </div>
                    </div>
                  );
                })()}

                {/* History Timeline */}
                <div className="glass-panel rounded-xl border border-white/10">
                  <div className="p-5 border-b border-white/5">
                    <h3 className="text-lg font-semibold text-white">Historique des audits</h3>
                  </div>
                  <div className="divide-y divide-white/5">
                    {history.map((entry, i) => (
                      <div key={entry.id} className="p-4 flex items-center justify-between hover:bg-white/[0.02] transition-colors">
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center text-lg font-bold text-white">
                            {entry.result.globalScore}
                          </div>
                          <div>
                            <p className="text-sm font-medium text-white">{entry.result.url}</p>
                            <p className="text-xs text-gray-500">
                              {new Date(entry.result.timestamp).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                            </p>
                          </div>
                        </div>
                        <div className="flex items-center gap-3">
                          {(['experience', 'expertise', 'authority', 'trust'] as const).map(p => (
                            <span key={p} className="text-xs font-mono" style={{ color: PILLAR_COLORS[p] }}>
                              {entry.result.scores[p]}
                            </span>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default EeatBuilder;
